contracts/Escrow.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@chainlink/contracts/src/v0.8/automation/AutomationCompatible.sol";

interface IAMLOracle {
    function getAMLScore(address buyer) external returns (uint256);
}

interface IPropertyToken {
    function mintTokens(uint256 propertyId, address buyer, uint256 amount) external;
    function getCurrentPrice(uint256 propertyId) external view returns (uint256);
    function getProperty(uint256 propertyId) external view returns (
        uint256 id,
        string memory name,
        string memory uri,
        uint256 totalSupply,
        uint256 mintedSupply,
        uint256 fundingTarget,
        uint256 fundingDeadline,
        uint8 currentPhase,
        bool isActive,
        bool isFunded
    );
    function markFunded(uint256 propertyId) external;
    function burnFromOnFailure(uint256 propertyId, address holder, uint256 amount) external;
    function balanceOf(address account, uint256 id) external view returns (uint256);
}

/**
 * @title RevitaHub Escrow
 * @notice Handles token purchases, 100% funding requirement, and 3% APR refunds
 * @dev Integrates with Chainlink Automation for deadline monitoring
 */
contract Escrow is AccessControl, ReentrancyGuard, Pausable, AutomationCompatibleInterface {
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");

    // 3% APR for refunds (in basis points)
    uint256 public constant REFUND_APR = 300;
    uint256 public constant BASIS_POINTS = 10000;
    uint256 public constant SECONDS_PER_YEAR = 365 days;

    uint256 public constant AML_THRESHOLD = 80;

    IPropertyToken public propertyToken;
    IAMLOracle public amlOracle;

    // Purchase record
    struct Purchase {
        address buyer;
        uint256 propertyId;
        uint256 amount;
        uint256 price;
        uint256 totalPaid;
        uint256 timestamp;
        bool refunded;
    }

    // Property escrow state
    struct PropertyEscrow {
        uint256 totalRaised;
        uint256 fundingTarget;
        uint256 deadline;
        bool isComplete;
        bool refundsProcessed;
    }

    // Storage
    mapping(uint256 => Purchase[]) public propertyPurchases;
    mapping(uint256 => PropertyEscrow) public propertyEscrows;
    mapping(uint256 => mapping(address => uint256)) public buyerContributions;

    // All property IDs for automation
    uint256[] public activeProperties;
    mapping(uint256 => bool) public isPropertyActive;

    // Dynamic funding targets based on poll demand
    mapping(uint256 => uint256) public pollDemandScores; // Poll demand in basis points (e.g., 8000 = 80% support)
    mapping(uint256 => uint256) public baseFundingTargets; // Original funding target before adjustment
    uint256 public constant MAX_DEMAND_BONUS = 2500; // Max 25% increase for high-demand properties

    // Events
    event PurchaseReceived(
        uint256 indexed propertyId,
        address indexed buyer,
        uint256 amount,
        uint256 totalPaid,
        uint256 timestamp
    );
    event FundingComplete(uint256 indexed propertyId, uint256 totalRaised);
    event RefundProcessed(
        uint256 indexed propertyId,
        address indexed buyer,
        uint256 principal,
        uint256 interest,
        uint256 total
    );
    event FundingFailed(uint256 indexed propertyId, uint256 totalRaised, uint256 target);
    event FundsReleased(uint256 indexed propertyId, address indexed recipient, uint256 amount);

    // Regulatory Compliance Events
    event CompliancePurchaseRecorded(
        uint256 indexed propertyId,
        address indexed buyer,
        uint256 amount,
        uint256 totalPaid,
        bytes32 transactionHash
    );
    event InvestorLimitChecked(
        uint256 indexed propertyId,
        address indexed investor,
        uint256 currentContribution,
        uint256 newContribution,
        bool withinLimit
    );
    event SuspiciousActivityReported(
        uint256 indexed propertyId,
        address indexed account,
        string activityType,
        uint256 timestamp
    );
    event RefundComplianceRecorded(
        uint256 indexed propertyId,
        address indexed recipient,
        uint256 principal,
        uint256 interest,
        uint256 timestamp
    );
    event PollDemandUpdated(
        uint256 indexed propertyId,
        uint256 demandScore,
        uint256 adjustedTarget
    );

    constructor(address _propertyToken) {
        propertyToken = IPropertyToken(_propertyToken);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(OPERATOR_ROLE, msg.sender);
    }

    /**
     * @notice Initialize escrow for a property
     * @param propertyId Property ID
     * @param fundingTarget Required funding amount
     * @param deadline Funding deadline timestamp
     */
    function initializeEscrow(
        uint256 propertyId,
        uint256 fundingTarget,
        uint256 deadline
    ) external onlyRole(OPERATOR_ROLE) {
        require(!isPropertyActive[propertyId], "Escrow already exists");

        // Store base target for potential dynamic adjustment
        baseFundingTargets[propertyId] = fundingTarget;

        propertyEscrows[propertyId] = PropertyEscrow({
            totalRaised: 0,
            fundingTarget: fundingTarget,
            deadline: deadline,
            isComplete: false,
            refundsProcessed: false
        });

        activeProperties.push(propertyId);
        isPropertyActive[propertyId] = true;
    }

    /**
     * @notice Update poll demand score and adjust funding target dynamically
     * @dev Higher demand = higher funding target (premium for popular properties)
     * @param propertyId Property ID
     * @param demandScore Poll support percentage in basis points (e.g., 8000 = 80%)
     */
    function updatePollDemand(uint256 propertyId, uint256 demandScore) external onlyRole(OPERATOR_ROLE) {
        require(isPropertyActive[propertyId], "Property not active");
        require(demandScore <= 10000, "Invalid demand score");

        PropertyEscrow storage escrow = propertyEscrows[propertyId];
        require(!escrow.isComplete, "Funding already complete");

        pollDemandScores[propertyId] = demandScore;

        // Calculate adjusted target: base + (base * demandBonus / 10000)
        // High demand (>70%) gets up to 25% higher target (premium property)
        uint256 baseTarget = baseFundingTargets[propertyId];
        uint256 demandBonus = 0;

        if (demandScore >= 7000) {
            // Scale bonus: 70% demand = 0%, 100% demand = 25%
            demandBonus = ((demandScore - 7000) * MAX_DEMAND_BONUS) / 3000;
        }

        uint256 adjustedTarget = baseTarget + (baseTarget * demandBonus) / 10000;
        escrow.fundingTarget = adjustedTarget;

        emit PollDemandUpdated(propertyId, demandScore, adjustedTarget);
    }

    /**
     * @notice Get demand-adjusted funding info
     * @param propertyId Property ID
     */
    function getDemandAdjustedTarget(uint256 propertyId) external view returns (
        uint256 baseTarget,
        uint256 adjustedTarget,
        uint256 demandScore
    ) {
        return (
            baseFundingTargets[propertyId],
            propertyEscrows[propertyId].fundingTarget,
            pollDemandScores[propertyId]
        );
    }

    /**
     * @notice Purchase tokens for a property
     * @param propertyId Property ID
     * @param amount Number of tokens to purchase
     */
    function purchase(uint256 propertyId, uint256 amount) external payable nonReentrant whenNotPaused {
        PropertyEscrow storage escrow = propertyEscrows[propertyId];
        require(isPropertyActive[propertyId], "Property not active");
        require(!escrow.isComplete, "Funding complete");
        require(block.timestamp < escrow.deadline, "Funding deadline passed");

        if (address(amlOracle) != address(0)) {
            uint256 amlScore = amlOracle.getAMLScore(msg.sender);
            if (amlScore > AML_THRESHOLD) {
                emit SuspiciousActivityReported(propertyId, msg.sender, "High AML Score", block.timestamp);
                revert("AML check failed");
            }
        }

        uint256 price = propertyToken.getCurrentPrice(propertyId);
        uint256 totalCost = price * amount;
        require(msg.value >= totalCost, "Insufficient payment");

        // Record purchase
        propertyPurchases[propertyId].push(Purchase({
            buyer: msg.sender,
            propertyId: propertyId,
            amount: amount,
            price: price,
            totalPaid: totalCost,
            timestamp: block.timestamp,
            refunded: false
        }));

        // Update escrow state
        escrow.totalRaised += totalCost;
        buyerContributions[propertyId][msg.sender] += totalCost;

        // Mint tokens to buyer
        propertyToken.mintTokens(propertyId, msg.sender, amount);

        // Refund excess payment
        if (msg.value > totalCost) {
            (bool success, ) = payable(msg.sender).call{value: msg.value - totalCost}("");
            require(success, "Refund failed");
        }

        emit PurchaseReceived(propertyId, msg.sender, amount, totalCost, block.timestamp);

        // Emit compliance event for regulatory reporting
        emit CompliancePurchaseRecorded(
            propertyId,
            msg.sender,
            amount,
            totalCost,
            keccak256(abi.encodePacked(block.timestamp, msg.sender, propertyId, amount))
        );

        // Emit investor limit check for AML monitoring
        emit InvestorLimitChecked(
            propertyId,
            msg.sender,
            buyerContributions[propertyId][msg.sender] - totalCost, // previous contribution
            buyerContributions[propertyId][msg.sender], // new total contribution
            true // withinLimit - would add threshold checking in production
        );

        // Check if funding target reached
        if (escrow.totalRaised >= escrow.fundingTarget) {
            _completeFunding(propertyId);
        }
    }

    /**
     * @notice Calculate refund with 3% APR interest
     * @param principal Original investment amount
     * @param investmentTimestamp When the investment was made
     */
    function calculateRefund(uint256 principal, uint256 investmentTimestamp) public view returns (uint256) {
        uint256 duration = block.timestamp - investmentTimestamp;
        uint256 interest = (principal * REFUND_APR * duration) / (BASIS_POINTS * SECONDS_PER_YEAR);
        return principal + interest;
    }

    /**
     * @notice Process refunds for a failed property funding
     * @param propertyId Property ID
     */
    function processRefunds(uint256 propertyId) external nonReentrant {
        PropertyEscrow storage escrow = propertyEscrows[propertyId];
        require(isPropertyActive[propertyId], "Property not active");
        require(!escrow.isComplete, "Funding was successful");
        require(block.timestamp >= escrow.deadline, "Deadline not reached");
        require(!escrow.refundsProcessed, "Refunds already processed");

        escrow.refundsProcessed = true;

        emit FundingFailed(propertyId, escrow.totalRaised, escrow.fundingTarget);

        // Process all refunds and burn tokens
        Purchase[] storage purchases = propertyPurchases[propertyId];
        for (uint256 i = 0; i < purchases.length; i++) {
            Purchase storage p = purchases[i];
            if (!p.refunded) {
                uint256 refundAmount = calculateRefund(p.totalPaid, p.timestamp);
                p.refunded = true;

                // Burn buyer's tokens
                uint256 tokenBalance = propertyToken.balanceOf(p.buyer, propertyId);
                if (tokenBalance > 0) {
                    propertyToken.burnFromOnFailure(propertyId, p.buyer, tokenBalance);
                }

                (bool success, ) = payable(p.buyer).call{value: refundAmount}("");
                require(success, "Refund transfer failed");

                emit RefundProcessed(
                    propertyId,
                    p.buyer,
                    p.totalPaid,
                    refundAmount - p.totalPaid,
                    refundAmount
                );

                // Emit compliance event for regulatory reporting
                emit RefundComplianceRecorded(
                    propertyId,
                    p.buyer,
                    p.totalPaid,
                    refundAmount - p.totalPaid,
                    block.timestamp
                );
            }
        }

        // Deactivate property
        isPropertyActive[propertyId] = false;
    }

    /**
     * @notice Internal function to complete funding
     * @param propertyId Property ID
     */
    function _completeFunding(uint256 propertyId) internal {
        PropertyEscrow storage escrow = propertyEscrows[propertyId];
        escrow.isComplete = true;

        propertyToken.markFunded(propertyId);

        emit FundingComplete(propertyId, escrow.totalRaised);
    }

    /**
     * @notice Release funds to property wallet after successful funding
     * @param propertyId Property ID
     * @param recipient Recipient address
     */
    function releaseFunds(uint256 propertyId, address recipient) external onlyRole(OPERATOR_ROLE) nonReentrant {
        PropertyEscrow storage escrow = propertyEscrows[propertyId];
        require(escrow.isComplete, "Funding not complete");
        require(escrow.totalRaised > 0, "No funds to release");

        uint256 amount = escrow.totalRaised;
        escrow.totalRaised = 0;
        isPropertyActive[propertyId] = false;

        (bool success, ) = payable(recipient).call{value: amount}("");
        require(success, "Transfer failed");

        emit FundsReleased(propertyId, recipient, amount);
    }

    /**
     * @notice Get purchase history for a property
     * @param propertyId Property ID
     */
    function getPurchases(uint256 propertyId) external view returns (Purchase[] memory) {
        return propertyPurchases[propertyId];
    }

    /**
     * @notice Get escrow status for a property
     * @param propertyId Property ID
     */
    function getEscrowStatus(uint256 propertyId) external view returns (
        uint256 totalRaised,
        uint256 fundingTarget,
        uint256 deadline,
        bool isComplete,
        uint256 percentFunded
    ) {
        PropertyEscrow storage escrow = propertyEscrows[propertyId];
        uint256 percent = escrow.fundingTarget > 0 
            ? (escrow.totalRaised * 10000) / escrow.fundingTarget 
            : 0;

        return (
            escrow.totalRaised,
            escrow.fundingTarget,
            escrow.deadline,
            escrow.isComplete,
            percent
        );
    }

    // ============ Chainlink Automation ============

    /**
     * @notice Chainlink Automation check for deadline monitoring
     */
    function checkUpkeep(bytes calldata) external view override returns (bool upkeepNeeded, bytes memory performData) {
        for (uint256 i = 0; i < activeProperties.length; i++) {
            uint256 propertyId = activeProperties[i];
            PropertyEscrow storage escrow = propertyEscrows[propertyId];

            if (isPropertyActive[propertyId] && 
                !escrow.isComplete && 
                !escrow.refundsProcessed &&
                block.timestamp >= escrow.deadline) {
                return (true, abi.encode(propertyId));
            }
        }
        return (false, "");
    }

    /**
     * @notice Chainlink Automation perform upkeep
     */
    function performUpkeep(bytes calldata performData) external override {
        uint256 propertyId = abi.decode(performData, (uint256));
        PropertyEscrow storage escrow = propertyEscrows[propertyId];

        // Re-validate conditions
        require(isPropertyActive[propertyId], "Property not active");
        require(!escrow.isComplete, "Funding complete");
        require(!escrow.refundsProcessed, "Refunds processed");
        require(block.timestamp >= escrow.deadline, "Deadline not reached");

        // Trigger refund processing
        this.processRefunds(propertyId);
    }

    /**
     * @notice Pause contract
     */
    function pause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _pause();
    }

    /**
     * @notice Unpause contract
     */
    function unpause() external onlyRole(DEFAULT_ADMIN_ROLE) {
        _unpause();
    }

    // ============ Regulatory Compliance Functions ============

    /**
     * @notice Report suspicious activity for compliance monitoring
     * @param propertyId Property ID
     * @param account Account involved
     * @param activityType Type of suspicious activity
     */
    function reportSuspiciousActivity(
        uint256 propertyId,
        address account,
        string calldata activityType
    ) external onlyRole(OPERATOR_ROLE) {
        emit SuspiciousActivityReported(propertyId, account, activityType, block.timestamp);
    }

    /**
     * @notice Get detailed purchase history for compliance audits
     * @param propertyId Property ID
     * @param index Purchase index
     */
    function getPurchaseForAudit(uint256 propertyId, uint256 index) external view returns (
        address buyer,
        uint256 amount,
        uint256 price,
        uint256 totalPaid,
        uint256 timestamp,
        bool refunded
    ) {
        require(index < propertyPurchases[propertyId].length, "Index out of bounds");
        Purchase storage p = propertyPurchases[propertyId][index];
        return (p.buyer, p.amount, p.price, p.totalPaid, p.timestamp, p.refunded);
    }

    /**
     * @notice Get purchase count for a property (for audit iteration)
     * @param propertyId Property ID
     */
    function getPurchaseCount(uint256 propertyId) external view returns (uint256) {
        return propertyPurchases[propertyId].length;
    }

    /**
     * @notice Get investor contribution total for AML monitoring
     * @param propertyId Property ID
     * @param investor Investor address
     */
    function getInvestorContribution(uint256 propertyId, address investor) external view returns (uint256) {
        return buyerContributions[propertyId][investor];
    }

    /**
     * @notice Set AML oracle address for automated compliance checks
     * @param _oracle Address of the AML oracle contract
     */
    function setAMLOracle(address _oracle) external onlyRole(DEFAULT_ADMIN_ROLE) {
        amlOracle = IAMLOracle(_oracle);
    }

    /**
     * @notice Required for receiving ETH for refund interest buffer
     */
    receive() external payable {}
}

contracts/PhaseManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/access/AccessControl.sol";
import "@chainlink/contracts/src/v0.8/automation/AutomationCompatible.sol";

interface IGeoOracle {
    function getPhaseEligibility(address user, uint256 propertyId) external returns (uint8);
}

interface IPropertyToken {
    enum Phase { County, State, National, International }

    function advancePhase(uint256 propertyId) external;
    function mintTokens(uint256 propertyId, address buyer, uint256 amount) external;
    function getProperty(uint256 propertyId) external view returns (
        uint256 id,
        string memory name,
        string memory uri,
        uint256 totalSupply,
        uint256 mintedSupply,
        uint256 fundingTarget,
        uint256 fundingDeadline,
        uint8 currentPhase,
        bool isActive,
        bool isFunded
    );
    function phaseAllocations(uint256 propertyId, uint8 phase) external view returns (uint256);
    function phaseMinted(uint256 propertyId, uint8 phase) external view returns (uint256);
    function whitelist(address account) external view returns (bool);
}

interface IGovernance {
    function proposalCount() external view returns (uint256);
    function getProposal(uint256 proposalId) external view returns (
        uint256 id,
        uint256 propertyId,
        address proposer,
        uint8 proposalType,
        string memory title,
        string memory description,
        string memory ipfsHash,
        uint256 votesFor,
        uint256 votesAgainst,
        uint256 votesAbstain,
        uint256 startTime,
        uint256 endTime,
        uint256 quorumRequired,
        uint8 status,
        bytes memory executionData
    );
    function getDemandBars() external view returns (uint256[4] memory);
    function getCommunityHealthScore() external view returns (uint256);
}

/**
 * @title RevitaHub Phase Manager
 * @notice Dynamic phase advancement based on engagement analytics
 * @dev Advances phases when 75% engagement threshold OR full subscription is reached
 */
contract PhaseManager is AccessControl, AutomationCompatibleInterface {
    bytes32 public constant OPERATOR_ROLE = keccak256("OPERATOR_ROLE");

    IPropertyToken public propertyToken;
    IGovernance public governance;
    IGeoOracle public geoOracle;

    // Engagement threshold for early phase advancement (basis points)
    uint256 public constant ENGAGEMENT_THRESHOLD = 7500; // 75%

    // Minimum engagement period before early advancement (prevents gaming)
    uint256 public constant MIN_ENGAGEMENT_PERIOD = 7 days;

    // Property engagement tracking
    struct PropertyEngagement {
        uint256 propertyId;
        uint256 phaseStartTime;
        uint256 totalEligibleVoters;
        uint256 activeVoters;
        uint256 totalProposals;
        uint256 votedProposals;
        bool isTracking;
    }

    // Engagement metrics per property
    mapping(uint256 => PropertyEngagement) public propertyEngagement;

    // Active properties for automation
    uint256[] public trackedProperties;
    mapping(uint256 => bool) public isTracked;

    // Behavioral nudge triggers
    mapping(uint256 => uint256) public lastNudgeTime;
    uint256 public nudgeCooldown = 24 hours;

    // Engagement bonus tracking (vote-to-earn)
    mapping(uint256 => mapping(address => bool)) public hasClaimed;
    uint256 public constant BONUS_TOKENS = 1; // Tokens awarded for engagement bonus

    // Poll participation bonuses
    mapping(uint256 => mapping(address => bool)) public pollParticipated; // Track poll voters
    mapping(uint256 => uint256) public propertyPollCount; // Number of polls per property
    uint256 public constant POLL_BONUS_MULTIPLIER = 50; // 0.5 extra engagement credit per poll vote (in basis points)

    // Events
    event EngagementUpdated(
        uint256 indexed propertyId,
        uint256 activeVoters,
        uint256 totalEligible,
        uint256 engagementPercent
    );
    event PhaseAdvancedByEngagement(
        uint256 indexed propertyId,
        uint8 fromPhase,
        uint8 toPhase,
        uint256 engagementPercent
    );
    event PhaseAdvancedBySubscription(
        uint256 indexed propertyId,
        uint8 fromPhase,
        uint8 toPhase
    );
    event NudgeTriggered(
        uint256 indexed propertyId,
        string nudgeType,
        uint256 engagementPercent
    );
    event PropertyTrackingStarted(uint256 indexed propertyId);
    event PropertyTrackingStopped(uint256 indexed propertyId);
    event BonusClaimed(uint256 indexed propertyId, address indexed claimer, uint256 bonus);
    event PollParticipationRecorded(uint256 indexed propertyId, address indexed participant);
    event PollBonusApplied(uint256 indexed propertyId, uint256 pollParticipants, uint256 bonusEngagement);
    event DemandNudge(uint256 indexed propertyId, uint8 demandType, uint256 demandBps);
    event DemandDrivenAdvancement(uint256 indexed propertyId, uint256 demandBps);
    event GeoEligibilityChecked(uint256 indexed propertyId, address indexed user, uint8 eligiblePhase);
    event GeoOracleUpdated(address indexed newOracle);

    constructor(address _propertyToken, address _governance) {
        propertyToken = IPropertyToken(_propertyToken);
        governance = IGovernance(_governance);
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(OPERATOR_ROLE, msg.sender);
    }

    /**
     * @notice Start tracking engagement for a property
     * @param propertyId Property ID
     * @param totalEligibleVoters Total number of eligible voters
     */
    function startTracking(uint256 propertyId, uint256 totalEligibleVoters) external onlyRole(OPERATOR_ROLE) {
        require(!isTracked[propertyId], "Already tracking");

        propertyEngagement[propertyId] = PropertyEngagement({
            propertyId: propertyId,
            phaseStartTime: block.timestamp,
            totalEligibleVoters: totalEligibleVoters,
            activeVoters: 0,
            totalProposals: 0,
            votedProposals: 0,
            isTracking: true
        });

        trackedProperties.push(propertyId);
        isTracked[propertyId] = true;

        emit PropertyTrackingStarted(propertyId);
    }

    /**
     * @notice Update engagement metrics for a property
     * @param propertyId Property ID
     * @param activeVoters Number of unique voters
     * @param totalProposals Total proposals for property
     * @param votedProposals Proposals with votes
     */
    function updateEngagement(
        uint256 propertyId,
        uint256 activeVoters,
        uint256 totalProposals,
        uint256 votedProposals
    ) external onlyRole(OPERATOR_ROLE) {
        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        require(engagement.isTracking, "Not tracking");

        engagement.activeVoters = activeVoters;
        engagement.totalProposals = totalProposals;
        engagement.votedProposals = votedProposals;

        uint256 engagementPercent = calculateEngagement(propertyId);
        emit EngagementUpdated(propertyId, activeVoters, engagement.totalEligibleVoters, engagementPercent);

        // Check for nudge triggers
        _checkNudges(propertyId, engagementPercent);

        // Check for early phase advancement
        _checkPhaseAdvancement(propertyId, engagementPercent);
    }

    /**
     * @notice Calculate engagement percentage
     * @param propertyId Property ID
     */
    function calculateEngagement(uint256 propertyId) public view returns (uint256) {
        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        if (engagement.totalEligibleVoters == 0) return 0;

        // Engagement = (active voters / eligible voters) * 100
        // Returns in basis points (e.g., 7500 = 75%)
        return (engagement.activeVoters * 10000) / engagement.totalEligibleVoters;
    }

    /**
     * @notice Check if phase should advance based on engagement
     * @param propertyId Property ID
     * @param engagementPercent Current engagement in basis points
     */
    function _checkPhaseAdvancement(uint256 propertyId, uint256 engagementPercent) internal {
        PropertyEngagement storage engagement = propertyEngagement[propertyId];

        // Check minimum engagement period
        if (block.timestamp < engagement.phaseStartTime + MIN_ENGAGEMENT_PERIOD) {
            return;
        }

        // Check engagement threshold
        if (engagementPercent >= ENGAGEMENT_THRESHOLD) {
            _advancePhaseByEngagement(propertyId, engagementPercent);
        }
    }

    /**
     * @notice Advance phase due to high engagement
     * @param propertyId Property ID
     * @param engagementPercent Engagement that triggered advancement
     */
    function _advancePhaseByEngagement(uint256 propertyId, uint256 engagementPercent) internal {
        (,,,,,,,uint8 currentPhase,,) = propertyToken.getProperty(propertyId);

        if (currentPhase < 3) { // Not at International yet
            propertyToken.advancePhase(propertyId);

            // Reset phase tracking
            propertyEngagement[propertyId].phaseStartTime = block.timestamp;
            propertyEngagement[propertyId].activeVoters = 0;

            emit PhaseAdvancedByEngagement(propertyId, currentPhase, currentPhase + 1, engagementPercent);
        }
    }

    /**
     * @notice Check and trigger behavioral nudges
     * @param propertyId Property ID
     * @param engagementPercent Current engagement
     */
    function _checkNudges(uint256 propertyId, uint256 engagementPercent) internal {
        if (block.timestamp < lastNudgeTime[propertyId] + nudgeCooldown) {
            return;
        }

        string memory nudgeType;

        if (engagementPercent < 2500) {
            // Low engagement - urgent nudge
            nudgeType = "urgent_participation";
        } else if (engagementPercent >= 6000 && engagementPercent < 7500) {
            // Near threshold - milestone nudge
            nudgeType = "milestone_near";
        } else if (engagementPercent >= 7000 && engagementPercent < 7500) {
            // Very close - final push nudge
            nudgeType = "phase_closing";
        } else {
            return; // No nudge needed
        }

        lastNudgeTime[propertyId] = block.timestamp;
        emit NudgeTriggered(propertyId, nudgeType, engagementPercent);
    }

    /**
     * @notice Manually trigger phase check (for subscription-based advancement)
     * @param propertyId Property ID
     */
    function checkSubscriptionAdvancement(uint256 propertyId) external {
        (,,,,,,,uint8 currentPhase,,) = propertyToken.getProperty(propertyId);

        if (address(geoOracle) != address(0)) {
            uint8 eligibility = geoOracle.getPhaseEligibility(msg.sender, propertyId);
            emit GeoEligibilityChecked(propertyId, msg.sender, eligibility);
        }

        uint256 phaseAllocation = propertyToken.phaseAllocations(propertyId, currentPhase);
        uint256 phaseMinted = propertyToken.phaseMinted(propertyId, currentPhase);

        if (phaseMinted >= phaseAllocation && currentPhase < 3) {
            propertyToken.advancePhase(propertyId);

            // Reset tracking for new phase
            propertyEngagement[propertyId].phaseStartTime = block.timestamp;
            propertyEngagement[propertyId].activeVoters = 0;

            emit PhaseAdvancedBySubscription(propertyId, currentPhase, currentPhase + 1);
        }
    }

    // ============ Chainlink Automation ============

    /**
     * @notice Chainlink Automation check
     */
    function checkUpkeep(bytes calldata) external view override returns (bool upkeepNeeded, bytes memory performData) {
        for (uint256 i = 0; i < trackedProperties.length; i++) {
            uint256 propertyId = trackedProperties[i];
            PropertyEngagement storage engagement = propertyEngagement[propertyId];

            if (!engagement.isTracking) continue;

            // Check if minimum period passed
            if (block.timestamp < engagement.phaseStartTime + MIN_ENGAGEMENT_PERIOD) continue;

            uint256 engagementPercent = calculateEngagement(propertyId);

            if (engagementPercent >= ENGAGEMENT_THRESHOLD) {
                return (true, abi.encode(propertyId, engagementPercent));
            }
        }
        return (false, "");
    }

    /**
     * @notice Chainlink Automation perform
     */
    function performUpkeep(bytes calldata performData) external override {
        (uint256 propertyId, ) = abi.decode(performData, (uint256, uint256));

        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        require(engagement.isTracking, "Not tracking");
        require(block.timestamp >= engagement.phaseStartTime + MIN_ENGAGEMENT_PERIOD, "Too early");

        // Re-verify engagement
        uint256 currentEngagement = calculateEngagement(propertyId);
        require(currentEngagement >= ENGAGEMENT_THRESHOLD, "Threshold not met");

        _advancePhaseByEngagement(propertyId, currentEngagement);
    }

    /**
     * @notice Stop tracking a property
     * @param propertyId Property ID
     */
    function stopTracking(uint256 propertyId) external onlyRole(OPERATOR_ROLE) {
        require(isTracked[propertyId], "Not tracking");

        propertyEngagement[propertyId].isTracking = false;
        isTracked[propertyId] = false;

        emit PropertyTrackingStopped(propertyId);
    }

    /**
     * @notice Update nudge cooldown
     * @param newCooldown New cooldown in seconds
     */
    function setNudgeCooldown(uint256 newCooldown) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(newCooldown >= 1 hours && newCooldown <= 7 days, "Invalid cooldown");
        nudgeCooldown = newCooldown;
    }

    /**
     * @notice Set geo-verification oracle for County-local eligibility checks
     * @param _oracle Address of the geo oracle contract
     */
    function setGeoOracle(address _oracle) external onlyRole(DEFAULT_ADMIN_ROLE) {
        geoOracle = IGeoOracle(_oracle);
        emit GeoOracleUpdated(_oracle);
    }

    /**
     * @notice Get all tracked properties
     */
    function getTrackedProperties() external view returns (uint256[] memory) {
        return trackedProperties;
    }

    /**
     * @notice Claim engagement bonus when threshold is met (vote-to-earn)
     * @dev Mints bonus tokens to active participants when 75% engagement is reached
     * @param propertyId Property ID
     */
    function claimEngagementBonus(uint256 propertyId) external {
        require(propertyToken.whitelist(msg.sender), "Not whitelisted");
        require(!hasClaimed[propertyId][msg.sender], "Already claimed");

        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        require(engagement.isTracking, "Not tracking");
        require(calculateEngagement(propertyId) >= ENGAGEMENT_THRESHOLD, "Threshold not met");
        require(block.timestamp >= engagement.phaseStartTime + MIN_ENGAGEMENT_PERIOD, "Too early");

        // Mark as claimed before minting (reentrancy protection)
        hasClaimed[propertyId][msg.sender] = true;

        uint256 bonusAmount = BONUS_TOKENS;

        // County locals get 1.5x bonus via geo-verification oracle
        if (address(geoOracle) != address(0)) {
            uint8 eligibility = geoOracle.getPhaseEligibility(msg.sender, propertyId);
            emit GeoEligibilityChecked(propertyId, msg.sender, eligibility);
            if (eligibility == 0) { // Phase.County = 0
                bonusAmount = (BONUS_TOKENS * 3) / 2; // 1.5x
            }
        }

        // Mint bonus tokens (requires MINTER_ROLE granted to PhaseManager)
        propertyToken.mintTokens(propertyId, msg.sender, bonusAmount);

        emit BonusClaimed(propertyId, msg.sender, bonusAmount);
    }

    /**
     * @notice Get engagement details for a property
     * @param propertyId Property ID
     */
    function getEngagement(uint256 propertyId) external view returns (
        uint256 phaseStartTime,
        uint256 totalEligible,
        uint256 activeVoters,
        uint256 engagementPercent,
        bool isTracking
    ) {
        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        return (
            engagement.phaseStartTime,
            engagement.totalEligibleVoters,
            engagement.activeVoters,
            calculateEngagement(propertyId),
            engagement.isTracking
        );
    }

    // ============ Poll Bonus Functions ============

    /**
     * @notice Record poll participation for engagement bonus credit
     * @dev Called by operator when user votes on a property-related poll
     * @param propertyId Property ID
     * @param participant Address of poll participant
     */
    function recordPollParticipation(
        uint256 propertyId,
        address participant
    ) external onlyRole(OPERATOR_ROLE) {
        require(isTracked[propertyId], "Property not tracked");
        require(!pollParticipated[propertyId][participant], "Already recorded");

        pollParticipated[propertyId][participant] = true;
        emit PollParticipationRecorded(propertyId, participant);
    }

    /**
     * @notice Update engagement with poll participation bonus
     * @dev Adds half-credit for poll voters to boost engagement calculation
     * @param propertyId Property ID
     * @param activeVoters Number of unique proposal voters
     * @param totalProposals Total proposals for property
     * @param votedProposals Proposals with votes
     * @param pollParticipants Number of unique poll voters
     */
    function updateEngagementWithPolls(
        uint256 propertyId,
        uint256 activeVoters,
        uint256 totalProposals,
        uint256 votedProposals,
        uint256 pollParticipants
    ) external onlyRole(OPERATOR_ROLE) {
        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        require(engagement.isTracking, "Not tracking");

        // Calculate poll bonus: half credit per poll voter
        // pollParticipants / 2 added to active voters (but not exceeding totalEligible)
        uint256 pollBonus = (pollParticipants * POLL_BONUS_MULTIPLIER) / 100;
        uint256 adjustedActiveVoters = activeVoters + pollBonus;

        // Cap at total eligible voters
        if (adjustedActiveVoters > engagement.totalEligibleVoters) {
            adjustedActiveVoters = engagement.totalEligibleVoters;
        }

        engagement.activeVoters = adjustedActiveVoters;
        engagement.totalProposals = totalProposals;
        engagement.votedProposals = votedProposals;

        uint256 engagementPercent = calculateEngagement(propertyId);
        emit EngagementUpdated(propertyId, adjustedActiveVoters, engagement.totalEligibleVoters, engagementPercent);
        emit PollBonusApplied(propertyId, pollParticipants, pollBonus);

        // Check for nudge triggers
        _checkNudges(propertyId, engagementPercent);

        // Check for early phase advancement
        _checkPhaseAdvancement(propertyId, engagementPercent);
    }

    /**
     * @notice Claim poll-boosted engagement bonus
     * @dev Extra bonus tokens for poll participants when threshold met
     * @param propertyId Property ID
     */
    function claimPollBoostBonus(uint256 propertyId) external {
        require(propertyToken.whitelist(msg.sender), "Not whitelisted");
        require(pollParticipated[propertyId][msg.sender], "Did not participate in polls");
        require(!hasClaimed[propertyId][msg.sender], "Already claimed");

        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        require(engagement.isTracking, "Not tracking");
        require(calculateEngagement(propertyId) >= ENGAGEMENT_THRESHOLD, "Threshold not met");
        require(block.timestamp >= engagement.phaseStartTime + MIN_ENGAGEMENT_PERIOD, "Too early");

        hasClaimed[propertyId][msg.sender] = true;

        // Poll participants get 2x bonus
        uint256 bonusAmount = BONUS_TOKENS * 2;
        propertyToken.mintTokens(propertyId, msg.sender, bonusAmount);

        emit BonusClaimed(propertyId, msg.sender, bonusAmount);
    }

    /**
     * @notice Check if user participated in polls for a property
     * @param propertyId Property ID
     * @param participant User address
     */
    function hasParticipatedInPolls(uint256 propertyId, address participant) external view returns (bool) {
        return pollParticipated[propertyId][participant];
    }

    // ============ Demand-Driven Engagement (SimCity Integration) ============

    /**
     * @notice Update engagement based on governance demand signals
     * @dev Reads demand bars from Governance contract, triggers phase advancement
     *      if PropertyDevelopment demand exceeds threshold. Like SimCity's advisor system.
     * @param propertyId Property ID to evaluate
     */
    function updateDemandEngagement(uint256 propertyId) external onlyRole(OPERATOR_ROLE) {
        require(isTracked[propertyId], "Property not tracked");
        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        require(engagement.isTracking, "Not tracking");

        // Get demand bars from Governance (SimCity-style RCI readings)
        uint256[4] memory demandBars = governance.getDemandBars();
        uint256 propDemandBps = demandBars[0]; // PropertyDevelopment = index 0

        // Emit advisor-style nudge for UI
        emit DemandNudge(propertyId, 0, propDemandBps);

        // Check if PropertyDevelopment demand meets engagement threshold
        if (propDemandBps >= ENGAGEMENT_THRESHOLD && 
            block.timestamp >= engagement.phaseStartTime + MIN_ENGAGEMENT_PERIOD) {
            _advancePhaseByEngagement(propertyId, propDemandBps);
            emit DemandDrivenAdvancement(propertyId, propDemandBps);
        }
    }

    /**
     * @notice Get community health from governance contract
     * @return healthScore 0-10000 based on demand diversity and participation
     */
    function getCommunityHealth() external view returns (uint256) {
        return governance.getCommunityHealthScore();
    }

    /**
     * @notice Get demand-adjusted engagement metrics for a property
     * @param propertyId Property ID
     * @return baseEngagement Standard engagement percentage in BPS
     * @return demandBars Governance demand bars [PropDev, Treasury, Params, Emergency]
     * @return healthScore Community health score 0-10000
     * @return isReadyForAdvancement Whether demand conditions support phase advancement
     */
    function getDemandEngagementMetrics(uint256 propertyId) external view returns (
        uint256 baseEngagement,
        uint256[4] memory demandBars,
        uint256 healthScore,
        bool isReadyForAdvancement
    ) {
        baseEngagement = calculateEngagement(propertyId);
        demandBars = governance.getDemandBars();
        healthScore = governance.getCommunityHealthScore();

        PropertyEngagement storage engagement = propertyEngagement[propertyId];
        isReadyForAdvancement = engagement.isTracking && 
            demandBars[0] >= ENGAGEMENT_THRESHOLD &&
            block.timestamp >= engagement.phaseStartTime + MIN_ENGAGEMENT_PERIOD;
    }
}

contracts/PropertyToken.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC1155/ERC1155.sol";
import "@openzeppelin/contracts/token/ERC1155/extensions/ERC1155Supply.sol";
import "@openzeppelin/contracts/token/ERC1155/extensions/ERC1155Burnable.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";
import "@openzeppelin/contracts/utils/Pausable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/structs/EnumerableSet.sol";

/**
 * @title RevitaHub Property Token
 * @notice ERC-1155 token for fractional real estate ownership
 * @dev Implements phase-based pricing, whitelist transfers, and per-property supply limits
 */
contract PropertyToken is ERC1155, ERC1155Supply, ERC1155Burnable, AccessControl, Pausable, ReentrancyGuard {
    using EnumerableSet for EnumerableSet.UintSet;

    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");
    bytes32 public constant PAUSER_ROLE = keccak256("PAUSER_ROLE");
    bytes32 public constant WHITELIST_ADMIN_ROLE = keccak256("WHITELIST_ADMIN_ROLE");
    bytes32 public constant PHASE_ADVANCER_ROLE = keccak256("PHASE_ADVANCER_ROLE");
    bytes32 public constant BURNER_ROLE = keccak256("BURNER_ROLE");

    // Property phases
    enum Phase { County, State, National, International }

    // Property structure
    struct Property {
        uint256 id;
        string name;
        string uri;
        uint256 totalSupply;
        uint256 mintedSupply;
        uint256 fundingTarget;
        uint256 fundingDeadline;
        Phase currentPhase;
        bool isActive;
        bool isFunded;
        string llcIdentifier;
        address custodian;
    }

    // Phase allocation percentages (basis points, 10000 = 100%)
    uint256 public constant COUNTY_ALLOCATION = 4000;    // 40%
    uint256 public constant STATE_ALLOCATION = 3000;     // 30%
    uint256 public constant NATIONAL_ALLOCATION = 2000;  // 20%
    uint256 public constant INTERNATIONAL_ALLOCATION = 1000; // 10%

    // Base price in wei ($12.50 equivalent, set by oracle)
    uint256 public basePrice = 12.5 ether / 1000; // Placeholder, updated by Chainlink

    // Phase price multipliers (basis points)
    uint256 public constant COUNTY_MULTIPLIER = 10000;      // 1.0x ($12.50)
    uint256 public constant STATE_MULTIPLIER = 15000;       // 1.5x ($18.75)
    uint256 public constant NATIONAL_MULTIPLIER = 22500;    // 2.25x ($28.13)
    uint256 public constant INTERNATIONAL_MULTIPLIER = 30000; // 3.0x ($37.50)

    // Voting power multipliers (basis points)
    uint256 public constant COUNTY_VOTING_MULTIPLIER = 15000;      // 1.5x
    uint256 public constant STATE_VOTING_MULTIPLIER = 12500;       // 1.25x
    uint256 public constant NATIONAL_VOTING_MULTIPLIER = 10000;    // 1.0x
    uint256 public constant INTERNATIONAL_VOTING_MULTIPLIER = 7500; // 0.75x

    // Property storage
    mapping(uint256 => Property) public properties;
    uint256 public propertyCount;

    // Phase allocations per property
    mapping(uint256 => mapping(Phase => uint256)) public phaseAllocations;
    mapping(uint256 => mapping(Phase => uint256)) public phaseMinted;

    // Whitelist for KYC-verified addresses
    mapping(address => bool) public whitelist;

    // Phase eligibility per address (based on location verification)
    mapping(address => Phase) public addressPhaseEligibility;

    // Token holdings with phase information
    mapping(uint256 => mapping(address => mapping(Phase => uint256))) public holdingsByPhase;

    // Track all property IDs for enumeration
    EnumerableSet.UintSet private _allPropertyIds;

    // Events
    event PropertyCreated(uint256 indexed propertyId, string name, uint256 totalSupply, uint256 fundingTarget, string llcIdentifier, address custodian);
    event PropertyFunded(uint256 indexed propertyId, uint256 totalRaised);
    event LLCBackingUpdated(uint256 indexed propertyId, string llcIdentifier, address custodian);
    event PhaseAdvanced(uint256 indexed propertyId, Phase newPhase);
    event TokensMinted(uint256 indexed propertyId, address indexed buyer, uint256 amount, Phase phase);
    event AddressWhitelisted(address indexed account, Phase eligibility);
    event AddressRemovedFromWhitelist(address indexed account);
    event BasePriceUpdated(uint256 newPrice);
    event TokensBurned(uint256 indexed propertyId, address indexed from, uint256 amount, Phase phase);

    // Regulatory Compliance Events
    event KYCVerificationCompleted(address indexed account, uint256 timestamp, bytes32 verificationId);
    event KYCVerificationRevoked(address indexed account, uint256 timestamp, string reason);
    event AMLCheckPassed(address indexed account, uint256 timestamp, bytes32 checkId);
    event AMLCheckFailed(address indexed account, uint256 timestamp, string reason);
    event ComplianceCheckpoint(uint256 indexed propertyId, uint256 timestamp, uint256 totalHolders, uint256 totalSupplyMinted);
    event TransferRestricted(uint256 indexed propertyId, address indexed from, address indexed to, string reason);
    event RegulatorAuditRequested(uint256 indexed propertyId, address indexed requestor, uint256 timestamp);

    // KYC/AML verification tracking
    mapping(address => bytes32) public kycVerificationIds;
    mapping(address => uint256) public kycVerificationTimestamps;
    mapping(address => bytes32) public amlCheckIds;

    constructor(string memory uri_) ERC1155(uri_) {
        _grantRole(DEFAULT_ADMIN_ROLE, msg.sender);
        _grantRole(MINTER_ROLE, msg.sender);
        _grantRole(PAUSER_ROLE, msg.sender);
        _grantRole(WHITELIST_ADMIN_ROLE, msg.sender);
        _grantRole(PHASE_ADVANCER_ROLE, msg.sender);
        _grantRole(BURNER_ROLE, msg.sender);
    }

    /**
     * @notice Burn tokens on failed funding (Escrow only)
     * @param propertyId Property ID
     * @param holder Address holding tokens to burn
     * @param amount Amount to burn
     */
    function burnFromOnFailure(
        uint256 propertyId,
        address holder,
        uint256 amount
    ) external onlyRole(BURNER_ROLE) {
        require(amount > 0, "Amount must be positive");
        require(balanceOf(holder, propertyId) >= amount, "Insufficient balance");

        // Burn bypasses normal transfer restrictions
        _burn(holder, propertyId, amount);
    }

    /**
     * @notice Create a new property token offering
     * @param name Property name
     * @param propertyUri Metadata URI
     * @param totalSupply Total tokens to mint
     * @param fundingTarget Amount in wei required for full funding
     * @param fundingDuration Duration in seconds for funding period
     */
    function createProperty(
        string memory name,
        string memory propertyUri,
        uint256 totalSupply,
        uint256 fundingTarget,
        uint256 fundingDuration,
        string memory llcId,
        address custodian
    ) external onlyRole(DEFAULT_ADMIN_ROLE) returns (uint256) {
        require(custodian != address(0), "Custodian required for LLC backing");
        require(bytes(llcId).length > 0, "LLC identifier required");

        uint256 propertyId = propertyCount++;

        properties[propertyId] = Property({
            id: propertyId,
            name: name,
            uri: propertyUri,
            totalSupply: totalSupply,
            mintedSupply: 0,
            fundingTarget: fundingTarget,
            fundingDeadline: block.timestamp + fundingDuration,
            currentPhase: Phase.County,
            isActive: true,
            isFunded: false,
            llcIdentifier: llcId,
            custodian: custodian
        });

        // Set phase allocations
        phaseAllocations[propertyId][Phase.County] = (totalSupply * COUNTY_ALLOCATION) / 10000;
        phaseAllocations[propertyId][Phase.State] = (totalSupply * STATE_ALLOCATION) / 10000;
        phaseAllocations[propertyId][Phase.National] = (totalSupply * NATIONAL_ALLOCATION) / 10000;
        phaseAllocations[propertyId][Phase.International] = (totalSupply * INTERNATIONAL_ALLOCATION) / 10000;

        // Track property for enumeration
        _allPropertyIds.add(propertyId);

        emit PropertyCreated(propertyId, name, totalSupply, fundingTarget, llcId, custodian);
        return propertyId;
    }

    /**
     * @notice Get the current price for a property based on phase
     * @param propertyId Property ID
     */
    function getCurrentPrice(uint256 propertyId) public view returns (uint256) {
        Property storage prop = properties[propertyId];
        require(prop.isActive, "Property not active");

        uint256 multiplier;
        if (prop.currentPhase == Phase.County) {
            multiplier = COUNTY_MULTIPLIER;
        } else if (prop.currentPhase == Phase.State) {
            multiplier = STATE_MULTIPLIER;
        } else if (prop.currentPhase == Phase.National) {
            multiplier = NATIONAL_MULTIPLIER;
        } else {
            multiplier = INTERNATIONAL_MULTIPLIER;
        }

        return (basePrice * multiplier) / 10000;
    }

    /**
     * @notice Get voting power multiplier for a phase
     * @param phase The phase to check
     */
    function getVotingMultiplier(Phase phase) public pure returns (uint256) {
        if (phase == Phase.County) return COUNTY_VOTING_MULTIPLIER;
        if (phase == Phase.State) return STATE_VOTING_MULTIPLIER;
        if (phase == Phase.National) return NATIONAL_VOTING_MULTIPLIER;
        return INTERNATIONAL_VOTING_MULTIPLIER;
    }

    /**
     * @notice Calculate voting power for an address on a property
     * @param propertyId Property ID
     * @param voter Address to check
     */
    function getVotingPower(uint256 propertyId, address voter) external view returns (uint256) {
        uint256 totalPower = 0;

        for (uint8 i = 0; i <= uint8(Phase.International); i++) {
            Phase phase = Phase(i);
            uint256 holdings = holdingsByPhase[propertyId][voter][phase];
            uint256 multiplier = getVotingMultiplier(phase);
            totalPower += (holdings * multiplier) / 10000;
        }

        return totalPower;
    }

    /**
     * @notice Calculate total weighted voting power for a property
     * @dev Sums all minted tokens by phase, weighted by voting multipliers
     * @param propertyId Property ID
     */
    function getTotalWeightedVotingPower(uint256 propertyId) external view returns (uint256) {
        uint256 totalPower = 0;

        for (uint8 i = 0; i <= uint8(Phase.International); i++) {
            Phase phase = Phase(i);
            uint256 minted = phaseMinted[propertyId][phase];
            uint256 multiplier = getVotingMultiplier(phase);
            totalPower += (minted * multiplier) / 10000;
        }

        return totalPower;
    }

    /**
     * @notice Mint tokens for a buyer (called by Escrow contract)
     * @param propertyId Property ID
     * @param buyer Buyer address
     * @param amount Number of tokens
     */
    function mintTokens(
        uint256 propertyId,
        address buyer,
        uint256 amount
    ) external onlyRole(MINTER_ROLE) nonReentrant whenNotPaused {
        require(whitelist[buyer], "Buyer not whitelisted");

        Property storage prop = properties[propertyId];
        require(prop.isActive, "Property not active");
        require(prop.custodian != address(0), "No LLC backing");
        require(!prop.isFunded || block.timestamp <= prop.fundingDeadline, "Funding closed");

        Phase buyerPhase = addressPhaseEligibility[buyer];
        require(uint8(buyerPhase) >= uint8(prop.currentPhase), "Not eligible for current phase");

        // Check phase allocation
        uint256 phaseRemaining = phaseAllocations[propertyId][prop.currentPhase] - 
                                 phaseMinted[propertyId][prop.currentPhase];
        require(amount <= phaseRemaining, "Exceeds phase allocation");

        // Mint tokens
        _mint(buyer, propertyId, amount, "");

        // Update state
        prop.mintedSupply += amount;
        phaseMinted[propertyId][prop.currentPhase] += amount;
        holdingsByPhase[propertyId][buyer][prop.currentPhase] += amount;

        emit TokensMinted(propertyId, buyer, amount, prop.currentPhase);

        // Check if phase is complete
        if (phaseMinted[propertyId][prop.currentPhase] >= phaseAllocations[propertyId][prop.currentPhase]) {
            _advancePhase(propertyId);
        }
    }

    /**
     * @notice Advance to next phase (can be called by PhaseManager)
     * @param propertyId Property ID
     */
    function advancePhase(uint256 propertyId) external onlyRole(PHASE_ADVANCER_ROLE) {
        _advancePhase(propertyId);
    }

    function _advancePhase(uint256 propertyId) internal {
        Property storage prop = properties[propertyId];
        require(prop.isActive, "Property not active");
        require(uint8(prop.currentPhase) < uint8(Phase.International), "Already at final phase");

        prop.currentPhase = Phase(uint8(prop.currentPhase) + 1);
        emit PhaseAdvanced(propertyId, prop.currentPhase);
    }

    /**
     * @notice Mark property as fully funded
     * @param propertyId Property ID
     */
    function markFunded(uint256 propertyId) external onlyRole(MINTER_ROLE) {
        Property storage prop = properties[propertyId];
        require(prop.isActive, "Property not active");
        require(!prop.isFunded, "Already funded");

        prop.isFunded = true;
        emit PropertyFunded(propertyId, prop.mintedSupply * getCurrentPrice(propertyId));
    }

    /**
     * @notice Add address to whitelist with phase eligibility
     * @param account Address to whitelist
     * @param eligibility Phase eligibility based on KYC/location
     */
    function addToWhitelist(address account, Phase eligibility) external onlyRole(WHITELIST_ADMIN_ROLE) {
        whitelist[account] = true;
        addressPhaseEligibility[account] = eligibility;
        emit AddressWhitelisted(account, eligibility);
    }

    /**
     * @notice Auto-whitelist with Chainlink Functions verification
     * @dev In production, verificationData contains Chainlink Functions proof (e.g., GA residency for County phase)
     * @param account Address to whitelist
     * @param eligibility Phase eligibility based on verified location
     * @param verificationData Chainlink Functions proof or location hash
     */
    function autoWhitelist(
        address account,
        Phase eligibility,
        bytes calldata verificationData
    ) external onlyRole(WHITELIST_ADMIN_ROLE) {
        // Placeholder: In production, call Chainlink Functions to verify (e.g., GA residency for County)
        // For now: Simple require or mock
        require(verificationData.length > 0, "No verification data");

        whitelist[account] = true;
        addressPhaseEligibility[account] = eligibility;
        emit AddressWhitelisted(account, eligibility);
    }

    /**
     * @notice Remove address from whitelist
     * @param account Address to remove
     */
    function removeFromWhitelist(address account) external onlyRole(WHITELIST_ADMIN_ROLE) {
        whitelist[account] = false;
        emit AddressRemovedFromWhitelist(account);
    }

    /**
     * @notice Update base price (called by Chainlink oracle)
     * @param newPrice New base price in wei
     */
    function updateBasePrice(uint256 newPrice) external onlyRole(DEFAULT_ADMIN_ROLE) {
        basePrice = newPrice;
        emit BasePriceUpdated(newPrice);
    }

    /**
     * @notice Update LLC backing for a property
     * @param propertyId Property ID
     * @param llcId LLC identifier (e.g., "GA-LLC-456")
     * @param custodian Custody wallet address
     */
    function updateLLCBacking(
        uint256 propertyId,
        string calldata llcId,
        address custodian
    ) external onlyRole(DEFAULT_ADMIN_ROLE) {
        require(properties[propertyId].isActive, "Property not active");
        require(custodian != address(0), "Custodian required");
        require(bytes(llcId).length > 0, "LLC identifier required");

        properties[propertyId].llcIdentifier = llcId;
        properties[propertyId].custodian = custodian;

        emit LLCBackingUpdated(propertyId, llcId, custodian);
    }

    /**
     * @notice Pause all token transfers
     */
    function pause() external onlyRole(PAUSER_ROLE) {
        _pause();
    }

    /**
     * @notice Unpause token transfers
     */
    function unpause() external onlyRole(PAUSER_ROLE) {
        _unpause();
    }

    /**
     * @notice Get property details
     * @param propertyId Property ID
     */
    function getProperty(uint256 propertyId) external view returns (Property memory) {
        return properties[propertyId];
    }

    /**
     * @notice Get all property IDs
     */
    function getAllPropertyIds() external view returns (uint256[] memory) {
        return _allPropertyIds.values();
    }

    /**
     * @notice Get property count
     */
    function getPropertyCount() external view returns (uint256) {
        return _allPropertyIds.length();
    }

    /**
     * @notice Check if property exists
     */
    function propertyExists(uint256 propertyId) external view returns (bool) {
        return _allPropertyIds.contains(propertyId);
    }

    // ============ Regulatory Compliance Functions ============

    /**
     * @notice Record KYC verification for an address
     * @param account Address that passed KYC
     * @param verificationId External verification ID from KYC provider
     */
    function recordKYCVerification(
        address account,
        bytes32 verificationId
    ) external onlyRole(WHITELIST_ADMIN_ROLE) {
        kycVerificationIds[account] = verificationId;
        kycVerificationTimestamps[account] = block.timestamp;
        emit KYCVerificationCompleted(account, block.timestamp, verificationId);
    }

    /**
     * @notice Revoke KYC verification for an address
     * @param account Address to revoke KYC
     * @param reason Reason for revocation
     */
    function revokeKYCVerification(
        address account,
        string calldata reason
    ) external onlyRole(WHITELIST_ADMIN_ROLE) {
        delete kycVerificationIds[account];
        delete kycVerificationTimestamps[account];
        whitelist[account] = false;
        emit KYCVerificationRevoked(account, block.timestamp, reason);
        emit AddressRemovedFromWhitelist(account);
    }

    /**
     * @notice Record AML check result
     * @param account Address that passed AML check
     * @param checkId External AML check ID
     */
    function recordAMLCheck(
        address account,
        bytes32 checkId
    ) external onlyRole(WHITELIST_ADMIN_ROLE) {
        amlCheckIds[account] = checkId;
        emit AMLCheckPassed(account, block.timestamp, checkId);
    }

    /**
     * @notice Record failed AML check
     * @param account Address that failed AML check
     * @param reason Reason for failure
     */
    function recordAMLFailure(
        address account,
        string calldata reason
    ) external onlyRole(WHITELIST_ADMIN_ROLE) {
        whitelist[account] = false;
        emit AMLCheckFailed(account, block.timestamp, reason);
        emit AddressRemovedFromWhitelist(account);
    }

    /**
     * @notice Create a compliance checkpoint for audit trail
     * @param propertyId Property ID to checkpoint
     */
    function createComplianceCheckpoint(uint256 propertyId) external onlyRole(DEFAULT_ADMIN_ROLE) {
        Property storage prop = properties[propertyId];
        require(prop.isActive, "Property not active");

        // Count unique holders (simplified - in production use a more efficient method)
        uint256 holderCount = 0; // Would need holder enumeration for actual count

        emit ComplianceCheckpoint(
            propertyId,
            block.timestamp,
            holderCount,
            prop.mintedSupply
        );
    }

    /**
     * @notice Request regulator audit (emits event for off-chain tracking)
     * @param propertyId Property ID for audit
     */
    function requestRegulatorAudit(uint256 propertyId) external onlyRole(DEFAULT_ADMIN_ROLE) {
        emit RegulatorAuditRequested(propertyId, msg.sender, block.timestamp);
    }

    /**
     * @notice Get KYC status for an address
     * @param account Address to check
     */
    function getKYCStatus(address account) external view returns (
        bool isVerified,
        bytes32 verificationId,
        uint256 verificationTimestamp
    ) {
        return (
            whitelist[account] && kycVerificationIds[account] != bytes32(0),
            kycVerificationIds[account],
            kycVerificationTimestamps[account]
        );
    }

    /**
     * @notice Override transfer to enforce whitelist, funding lock, and maintain phase tracking
     */
    function _update(
        address from,
        address to,
        uint256[] memory ids,
        uint256[] memory values
    ) internal virtual override(ERC1155, ERC1155Supply) whenNotPaused {
        // Allow minting (from == address(0)) and burning (to == address(0))
        // For regular transfers, enforce whitelist AND funding completion
        if (from != address(0) && to != address(0)) {
            // Check each property being transferred
            for (uint256 i = 0; i < ids.length; i++) {
                uint256 propertyId = ids[i];
                // Block transfers until property is fully funded (investor protection)
                require(properties[propertyId].isFunded, "Transfers locked during funding");
            }
            require(whitelist[to], "Recipient not whitelisted");
        }

        // Handle transfers and burns - update holdingsByPhase
        if (from != address(0)) {
            for (uint256 i = 0; i < ids.length; i++) {
                uint256 propertyId = ids[i];
                uint256 amount = values[i];

                // Deduct from sender's phase holdings (FIFO - earliest phase first)
                uint256 remaining = amount;
                for (uint8 p = 0; p <= uint8(Phase.International) && remaining > 0; p++) {
                    Phase phase = Phase(p);
                    uint256 holdings = holdingsByPhase[propertyId][from][phase];
                    if (holdings > 0) {
                        uint256 toDeduct = holdings > remaining ? remaining : holdings;
                        holdingsByPhase[propertyId][from][phase] -= toDeduct;

                        // For burns (to == address(0)), also update global state
                        if (to == address(0)) {
                            properties[propertyId].mintedSupply -= toDeduct;
                            phaseMinted[propertyId][phase] -= toDeduct;
                            emit TokensBurned(propertyId, from, toDeduct, phase);
                        } else {
                            // For transfers, add to recipient's phase holdings
                            holdingsByPhase[propertyId][to][phase] += toDeduct;
                        }

                        remaining -= toDeduct;
                    }
                }

                // Revert if we couldn't account for all tokens
                require(remaining == 0, "Insufficient phase-tracked holdings");
            }
        }

        super._update(from, to, ids, values);
    }

    /**
     * @notice Required override for AccessControl
     */
    function supportsInterface(bytes4 interfaceId)
        public
        view
        override(ERC1155, AccessControl)
        returns (bool)
    {
        return super.supportsInterface(interfaceId);
    }
}

